mapper.insert:
/* wif-wcs-locationmaster-interface-sql-oracle.xml - insertPickingToteComplete - 피킹토트 WCS I/F Sequence 조회 SQL */
INSERT INTO TWIF_WCS_PKCOMPL
(
	WCSSEQ
	,CTKEY
	,OWKEY
	,TOTEBRCD
	,DASBRLOC
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
	,IFRETRYYN
	,IFRETRYIFID
)
VALUES(
	#{wcsSeq}
	,#{ctKey}
	,#{owKey}
	,#{toteBrcd}
	,#{dasBrLoc}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{ifretryyn}
	,#{ifretryifid}
)

mapper.update:
/* wif-wcs-locationmaster-interface-sql-oracle.xml - updateInterfaceStatusWcsResult - WCS Interface Result UPDATE SQL */
UPDATE ${tableName}
   SET IFSTATUS		= #{ifStatus}
	   ,IFERRCD		= #{ifErrCd}
	   ,IFERRMSG	= #{ifErrMsg}
	   ,IFPRCSDATE	= #{sysdate}
	   ,UPDATEDATE  = #{sysdate}
	   ,UPDATEURKEY = #{surkey}
 WHERE WCSSEQ 		= #{wcsSeq}
